  1	import React, { FC, useCallback, useState } from 'react';
  2	
  3	import { produceVMNetworks, useWizardVMContext } from '@catalog/utils/WizardVMContext';
  4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import ConfirmActionMessage from '@kubevirt-utils/components/ConfirmActionMessage/ConfirmActionMessage';
  6	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
  7	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
  8	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
  9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 10	import { getInterfaces, getNetworks } from '@kubevirt-utils/resources/vm';
 11	import { NetworkPresentation } from '@kubevirt-utils/resources/vm/utils/network/constants';
 12	import { isEmpty } from '@kubevirt-utils/utils/utils';
 13	import { ButtonVariant, Dropdown, DropdownItem, DropdownList } from '@patternfly/react-core';
 14	
 15	import WizardEditNetworkInterfaceModal from '../modal/WizardEditNetworkInterfaceModal';
 16	
 17	type NetworkInterfaceActionsProps = {
 18	  nicName: string;
 19	  nicPresentation: NetworkPresentation;
 20	  onUpdateVM?: (updateVM: V1VirtualMachine) => Promise<void>;
 21	  vm: V1VirtualMachine;
 22	};
 23	
 24	const NetworkInterfaceActions: FC<NetworkInterfaceActionsProps> = ({
 25	  nicName,
 26	  nicPresentation,
 27	  onUpdateVM,
 28	  vm,
 29	}) => {
 30	  const { t } = useKubevirtTranslation();
 31	  const { updateVM } = useWizardVMContext();
 32	  const { createModal } = useModal();
 33	  const onUpdate = onUpdateVM || updateVM;
 34	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
 35	  const label = t('Delete NIC?');
 36	  const editBtnText = t('Edit');
 37	  const submitBtnText = t('Delete');
 38	
 39	  const onEditModalOpen = () => {
 40	    createModal(({ isOpen, onClose }) => (
 41	      <WizardEditNetworkInterfaceModal
 42	        isOpen={isOpen}
 43	        nicPresentation={nicPresentation}
 44	        onClose={onClose}
 45	        updateVM={onUpdate}
 46	        vm={vm}
 47	      />
 48	    ));
 49	
 50	    setIsDropdownOpen(false);
 51	  };
 52	
 53	  const onDelete = useCallback(() => {
 54	    const updatedVM = produceVMNetworks(vm, (draftVM) => {
 55	      const vmInterfaces = getInterfaces(draftVM);
 56	      if (isEmpty(vmInterfaces)) {
 57	        draftVM.spec.template.spec.domain.devices.autoattachPodInterface = false;
 58	        return;
 59	      }
 60	
 61	      draftVM.spec.template.spec.networks = getNetworks(draftVM)?.filter(
 62	        ({ name }) => name !== nicName,
 63	      );
 64	      draftVM.spec.template.spec.domain.devices.interfaces = vmInterfaces?.filter(
 65	        ({ name }) => name !== nicName,
 66	      );
 67	    });
 68	    return onUpdate(updatedVM);
 69	  }, [nicName, onUpdate, vm]);
 70	
 71	  const onDeleteModalToggle = () => {
 72	    createModal(({ isOpen, onClose }) => (
 73	      <TabModal<V1VirtualMachine>
 74	        headerText={label}
 75	        isOpen={isOpen}
 76	        obj={vm}
 77	        onClose={onClose}
 78	        onSubmit={onDelete}
 79	        submitBtnText={submitBtnText}
 80	        submitBtnVariant={ButtonVariant.danger}
 81	      >
 82	        <ConfirmActionMessage
 83	          obj={{ metadata: { name: nicName, namespace: vm?.metadata?.namespace } }}
 84	        />
 85	      </TabModal>
 86	    ));
 87	    setIsDropdownOpen(false);
 88	  };
 89	
 90	  const onToggle = () => setIsDropdownOpen((prevIsOpen) => !prevIsOpen);
 91	  return (
 92	    <Dropdown
 93	      isOpen={isDropdownOpen}
 94	      onOpenChange={(open: boolean) => setIsDropdownOpen(open)}
 95	      onSelect={() => setIsDropdownOpen(false)}
 96	      toggle={KebabToggle({ id: 'toggle-id-network', onClick: onToggle })}
 97	    >
 98	      <DropdownList>
 99	        <DropdownItem key="network-interface-edit" onClick={onEditModalOpen}>
100	          {editBtnText}
101	        </DropdownItem>
102	        <DropdownItem key="network-interface-delete" onClick={onDeleteModalToggle}>
103	          {submitBtnText}
104	        </DropdownItem>
105	      </DropdownList>
106	    </Dropdown>
107	  );
108	};
109	
110	export default NetworkInterfaceActions;

